// src/components/Header/Header.jsx
import { Link } from 'react-router-dom';
import '../../index';

export default function Header() {
  return (
    <header className="header">
      <div className="container">
        <div className="header-inner">

          {/* Logo + Brand */}
          <div className="header-brand">
            <svg className="header-logo-icon" fill="currentColor" viewBox="0 0 48 48">
              <path d="M8.57829 8.57829C5.52816 11.6284 3.451 15.5145 2.60947 19.7452C1.76794 23.9758 2.19984 28.361 3.85056 32.3462C5.50128 36.3314 8.29667 39.7376 11.8832 42.134C15.4698 44.5305 19.6865 45.8096 24 45.8096C28.3135 45.8096 32.5302 44.5305 36.1168 42.134C39.7033 39.7375 42.4987 36.3314 44.1494 32.3462C45.8002 28.361 46.2321 23.9758 45.3905 19.7452C44.549 15.5145 42.4718 11.6284 39.4217 8.57829L24 24L8.57829 8.57829Z"></path>
            </svg>
            <Link to="/" className="header-brand-name">TunisiaED</Link>
          </div>

          {/* Desktop Nav */}
          <nav className="header-nav">
            <Link to="/courses" className="nav-link">Courses</Link>
            <Link to="/roadmaps" className="nav-link">Roadmaps</Link>
            <Link to="/resources" className="nav-link">Resources</Link>
            <Link to="/instructors" className="nav-link">Instructors</Link>
            <Link to="/community" className="nav-link">Community Forums</Link>
            <Link to="/pricing" className="nav-link">Subscriptions</Link>
          </nav>

          {/* Actions */}
          <div className="header-actions">
            <Link to="/signup" className="btn-accent">Sign Up</Link>
            <Link to="/login" className="btn-secondary">Login</Link>
            <div className="header-avatar" />
          </div>

        </div>
      </div>
    </header>
  );
}
